    pub(super) async fn create_ec2_route_table(
        &self,
        config: &serde_json::Value,
    ) -> Result<ResourceOutput, ProviderError> {
        let vpc_id = config.require_str("/network/vpc_id")?;

        let tag_spec = Self::build_tags(config, aws_sdk_ec2::types::ResourceType::RouteTable);

        let result = self
            .ec2_client
            .create_route_table()
            .vpc_id(vpc_id)
            .tag_specifications(tag_spec)
            .send()
            .await
            .map_err(|e| ProviderError::ApiError(format!("CreateRouteTable: {e}")))?;

        let rt = result
            .route_table()
            .ok_or_else(|| ProviderError::ApiError("CreateRouteTable returned no table".into()))?;
        let rt_id = rt
            .route_table_id()
            .ok_or_else(|| ProviderError::ApiError("RouteTable has no ID".into()))?;

        // Add routes from config
        if let Some(routes) = config.optional_array("/network/routes") {
            for route in routes {
                let dest = route.str_or("/destination_cidr", "0.0.0.0/0");

                let mut req = self
                    .ec2_client
                    .create_route()
                    .route_table_id(rt_id)
                    .destination_cidr_block(dest);

                if let Some(gw) = route
                    .get("gateway_id")
                    .and_then(|v| v.as_str())
                    .or_else(|| config.get("gateway_id").and_then(|v| v.as_str()))
                {
                    req = req.gateway_id(gw);
                } else if let Some(nat) = route
                    .get("nat_gateway_id")
                    .and_then(|v| v.as_str())
                    .or_else(|| config.get("nat_gateway_id").and_then(|v| v.as_str()))
                {
                    req = req.nat_gateway_id(nat);
                }

                req.send()
                    .await
                    .map_err(|e| ProviderError::ApiError(format!("CreateRoute: {e}")))?;
            }
        }

        let provider_id = rt_id;

        self.read_ec2_route_table(provider_id).await
    }

    pub(super) async fn read_ec2_route_table(
        &self,
        provider_id: &str,
    ) -> Result<ResourceOutput, ProviderError> {
        let result = self
            .ec2_client
            .describe_route_tables()
            .route_table_ids(provider_id)
            .send()
            .await
            .map_err(|e| ProviderError::ApiError(format!("DescribeRouteTables: {e}")))?;

        let rt = result
            .route_tables()
            .first()
            .ok_or_else(|| ProviderError::NotFound(format!("RouteTable {provider_id}")))?;

        let routes: Vec<serde_json::Value> = rt
            .routes()
            .iter()
            .filter(|r| r.gateway_id() != Some("local"))
            .map(|r| {
                let mut route = serde_json::json!({
                    "destination_cidr": r.destination_cidr_block().unwrap_or(""),
                });
                if let Some(gw) = r.gateway_id() {
                    route["gateway_id"] = serde_json::json!(gw);
                }
                if let Some(nat) = r.nat_gateway_id() {
                    route["nat_gateway_id"] = serde_json::json!(nat);
                }
                route
            })
            .collect();

        let state = serde_json::json!({
            "identity": { "name": super::extract_name_tag(rt.tags()) },
            "network": {
                "vpc_id": rt.vpc_id().unwrap_or(""),
                "routes": routes,
            }
        });

        let mut outputs = HashMap::new();
        outputs.insert("route_table_id".into(), serde_json::json!(provider_id));

        Ok(ResourceOutput {
            provider_id: provider_id.to_string(),
            state,
            outputs,
        })
    }

    pub(super) async fn update_ec2_route_table(
        &self,
        provider_id: &str,
        config: &serde_json::Value,
    ) -> Result<ResourceOutput, ProviderError> {
        // Delete existing non-local routes, then re-add from config
        let current = self
            .ec2_client
            .describe_route_tables()
            .route_table_ids(provider_id)
            .send()
            .await
            .map_err(|e| ProviderError::ApiError(format!("DescribeRouteTables: {e}")))?;

        if let Some(rt) = current.route_tables().first() {
            for route in rt.routes() {
                if route.gateway_id() == Some("local") {
                    continue;
                }
                if let Some(dest) = route.destination_cidr_block() {
                    let _ = self
                        .ec2_client
                        .delete_route()
                        .route_table_id(provider_id)
                        .destination_cidr_block(dest)
                        .send()
                        .await;
                }
            }
        }

        // Re-add routes
        if let Some(routes) = config.optional_array("/network/routes") {
            for route in routes {
                let dest = route.str_or("/destination_cidr", "0.0.0.0/0");
                let mut req = self
                    .ec2_client
                    .create_route()
                    .route_table_id(provider_id)
                    .destination_cidr_block(dest);
                if let Some(gw) = route
                    .get("gateway_id")
                    .and_then(|v| v.as_str())
                    .or_else(|| config.get("gateway_id").and_then(|v| v.as_str()))
                {
                    req = req.gateway_id(gw);
                } else if let Some(nat) = route
                    .get("nat_gateway_id")
                    .and_then(|v| v.as_str())
                    .or_else(|| config.get("nat_gateway_id").and_then(|v| v.as_str()))
                {
                    req = req.nat_gateway_id(nat);
                }
                req.send()
                    .await
                    .map_err(|e| ProviderError::ApiError(format!("CreateRoute: {e}")))?;
            }
        }

        self.read_ec2_route_table(provider_id).await
    }

